import re

def scan_prompt_injection(user_message):
    jailbreak_patterns = [
        r'(ignore|forget|override).*?instructions',
        r'(you are|pretend).*?(hacker|developer|admin)',
        r'(bypass|disable).*?(safety|guardrails)',
        r'(!+|\*+|===).*?(do|execute|run)'
    ]

    matches = []
    for pattern in jailbreak_patterns:
        if re.search(pattern, user_message, re.IGNORECASE):
            matches.append(pattern)

    return {
        'injections_found': len(matches),
        'patterns_matched': matches,
        'risk_score': min(len(matches) * 20, 100)
    }

def filter_tool_output(tool_output):
    sensitive_patterns = [
        r'\b(API|secret|key|token|password)[s]?:\s*[^\s]+',
        r'\b(?:[a-zA-Z0-9+/]{4})*(?:[a-zA-Z0-9+/]{2}==|[a-zA-Z0-9+/]{3}=)?$',
        r'PRIVATE KEY|AWS_ACCESS_KEY',
        r'\b(?:\d[\d\-\s]*?){15,}\b'
    ]

    leaks = []
    for pattern in sensitive_patterns:
        matches = re.findall(pattern, tool_output, re.MULTILINE)
        leaks.extend(matches)

    return {
        'data_leaks_detected': bool(leaks),
        'leaked_content': leaks,
        'sanitized_output': re.sub('|'.join(sensitive_patterns), '[REDACTED]', tool_output)
    }

