import anthropic

class SafeClaudeAgent:
    def __init__(self, client, allowed_tools):
        self.client = client
        self.allowed_tools = set(allowed_tools)

    def safe_message_create(self, messages, **kwargs):
        response = self.client.messages.create(
            model='claude-3-5-sonnet-20240620',
            messages=messages,
            tools=[{'name': name} for name in self.allowed_tools],
            **kwargs
        )

        # Block unauthorized tool calls
        if response.tool_calls:
            for tool_call in response.tool_calls:
                if tool_call['name'] not in self.allowed_tools:
                    raise ValueError(f'Unauthorized tool: {tool_call["name"]}')

        return response

import re

def sanitize_user_input(raw_input):
    # Remove common jailbreak prefixes/suffixes
    cleaned = re.sub(
        r'^(ignore previous|forget|override|.*?[!*]{3,}).*?(instructions|rules):?\s*',
        '', raw_input, flags=re.IGNORECASE | re.MULTILINE
    )

    # Strip role-playing directives
    cleaned = re.sub(
        r'^(you are|pretend you are|act as).*?\n*', '', cleaned, flags=re.IGNORECASE
    )

    return cleaned.strip()
